sp_angular_provider.script:
function scmReference() {
    "use_strict";
    return {
        restrict: "E",
        replace: true,
        require: "ngModel",
        scope: {
            label: "@",
            placeholder: "@",
            scmTable: "@",
            scmReferenceQualifier: "@?",
            scmDisplayFields: "@?",
            scmRequired: "=?",
        },

        template: `
            <sdx-select
                label="{{label}}"
                placeholder="{{placeholder}}"
                loading="{{isLoading}}"
                keyboard-behavior="filter"
                filter-min-length="2"
                ng-required="scmRequired">

                <sdx-select-option 
                    ng-repeat="option in options" 
                    value="{{option.value}}">
                    {{option.label}}
                </sdx-select-option>
            </sdx-select>
        `,
        link: (scope, element, attrs, ngModelCtrl) => {
            function setSelectedOption(value) {
                setTimeout(() => {
                    const sdxSelectOptions =
                        element[0].querySelectorAll("sdx-select-option");

                    sdxSelectOptions.forEach((option) => {
                        option.removeAttribute("selected");
                    });

                    if (value) {
                        sdxSelectOptions.forEach((option) => {
                            if (option.getAttribute("value") === value) {
                                option.setAttribute("selected", "true");
                            }
                        });
                    }
                }, 50);
            }

            function setupEventListener() {
                const sdxSelect =
                    element[0].querySelector("sdx-select") || element[0];

                if (sdxSelect) {
                    sdxSelect.changeCallback = function (value) {
                        setTimeout(() => {
                            scope.$apply(function () {
                                const currentValue = sdxSelect.value;
                                const newValue =
                                    currentValue && currentValue.length > 0
                                        ? currentValue[0]
                                        : null;

                                ngModelCtrl.$setViewValue(newValue);
                                ngModelCtrl.$setDirty();
                                ngModelCtrl.$setTouched();
                                setSelectedOption(newValue);
                            });
                        }, 100);
                    };

                    return true;
                }
                return false;
            }

            if (!setupEventListener()) {
                setTimeout(() => setupEventListener(), 100);
            }

            ngModelCtrl.$render = function () {
                const modelValue = ngModelCtrl.$viewValue;
                const sdxSelect =
                    element[0].querySelector("sdx-select") || element[0];

                if (modelValue) {
                    if (sdxSelect && sdxSelect.value !== undefined) {
                        sdxSelect.value = [modelValue];
                    }
                    setSelectedOption(modelValue);
                } else {
                    if (sdxSelect && sdxSelect.value !== undefined) {
                        sdxSelect.value = [];
                    }
                    setSelectedOption(null);
                }
            };

            scope.$watch("options", function (newOptions) {
                if (
                    newOptions &&
                    newOptions.length > 0 &&
                    ngModelCtrl.$viewValue
                ) {
                    setSelectedOption(ngModelCtrl.$viewValue);
                }
            });
        },
        controller: ($scope, $http) => {
            $scope.options = [];
            $scope.isLoading = false;

            $scope.loadOptions = function () {
                if (!$scope.scmTable) {
                    console.warn("scmReference: table parameter is required");
                    return;
                }

                $scope.isLoading = true;

                let apiUrl = "/api/now/table/" + $scope.scmTable;
                let params = [];

                if ($scope.scmReferenceQualifier) {
                    params.push(
                        "sysparm_query=" +
                            encodeURIComponent($scope.scmReferenceQualifier),
                    );
                }

                params.push("sysparm_display_value=all");

                let fields = ["sys_id"];
                if ($scope.scmDisplayFields) {
                    fields = fields.concat($scope.scmDisplayFields.split(","));
                }
                params.push(
                    "sysparm_fields=" + encodeURIComponent(fields.join(",")),
                );

                params.push("sysparm_limit=10");

                if (params.length > 0) {
                    apiUrl += "?" + params.join("&");
                }

                $http
                    .get(apiUrl)
                    .then(function (response) {
                        if (response.data && response.data.result) {
                            $scope.options = response.data.result.map(
                                function (record) {
                                    let label = "";

                                    if ($scope.scmDisplayFields) {
                                        let displayFields =
                                            $scope.scmDisplayFields
                                                .split(",")
                                                .map((field) => field.trim());
                                        let displayValues = [];

                                        displayFields.forEach(function (field) {
                                            if (
                                                record[field] &&
                                                record[field].display_value
                                            ) {
                                                displayValues.push(
                                                    record[field].display_value,
                                                );
                                            }
                                        });

                                        label = displayValues.join(", ");
                                    } else {
                                        label = record.sys_id.value;
                                    }

                                    return {
                                        value: record.sys_id.value,
                                        label: label || record.sys_id.value,
                                    };
                                },
                            );
                        }
                    })
                    .catch(function (error) {
                        console.error(
                            "scmReference: Error loading options",
                            error,
                        );
                    })
                    .finally(function () {
                        $scope.options.unshift({
                            value: "",
                            label: "-- None --",
                        });
                        $scope.isLoading = false;
                    });
            };

            $scope.loadOptions();
        },
    };
}
